// Compile monthly report
const items = $input.all();
const weeklyTraffic = items.filter(i => i.json.week).map(i => i.json);
const rankingChanges = items.filter(i => i.json.keyword && i.json.improvement !== undefined).map(i => i.json);
const backlinkSummary = items.find(i => i.json.total_backlinks !== undefined)?.json || {};

const lastMonth = new Date();
lastMonth.setMonth(lastMonth.getMonth() - 1);
const monthName = lastMonth.toLocaleString('default', { month: 'long', year: 'numeric' });

const totalSessions = weeklyTraffic.reduce((sum, w) => sum + (w.sessions || 0), 0);
const totalUsers = weeklyTraffic.reduce((sum, w) => sum + (w.users || 0), 0);
const totalPageviews = weeklyTraffic.reduce((sum, w) => sum + (w.pageviews || 0), 0);

const improved = rankingChanges.filter(r => r.improvement > 0);
const declined = rankingChanges.filter(r => r.improvement < 0);

const report = {
  report_type: 'monthly_report',
  period_start: new Date(lastMonth.getFullYear(), lastMonth.getMonth(), 1).toISOString().split('T')[0],
  period_end: new Date(lastMonth.getFullYear(), lastMonth.getMonth() + 1, 0).toISOString().split('T')[0],
  title: `Web Intelligence Monthly Report - ${monthName}`,
  summary: `Traffic: ${totalSessions.toLocaleString()} sessions | Rankings: ${improved.length} improved, ${declined.length} declined | Backlinks: ${backlinkSummary.total_backlinks || 0} total`,
  metrics_snapshot: JSON.stringify({
    traffic: { sessions: totalSessions, users: totalUsers, pageviews: totalPageviews },
    rankings: { improved: improved.length, declined: declined.length },
    backlinks: backlinkSummary
  }),
  highlights: JSON.stringify([
    { type: 'metric', message: `${totalSessions.toLocaleString()} total sessions` },
    { type: 'metric', message: `${improved.length} keywords improved in rankings` },
    { type: 'metric', message: `${backlinkSummary.new_last_30_days || 0} new backlinks acquired` }
  ]),
  status: 'generated',
  slack_message: `:calendar: *Monthly Web Intelligence Report - ${monthName}*\n\n:chart_with_upwards_trend: *Traffic Summary*\n• Sessions: ${totalSessions.toLocaleString()}\n• Users: ${totalUsers.toLocaleString()}\n• Pageviews: ${totalPageviews.toLocaleString()}\n\n:dart: *Ranking Performance*\n• Keywords Improved: ${improved.length}\n• Keywords Declined: ${declined.length}\n• Top Improver: ${improved[0]?.keyword || 'N/A'} (+${improved[0]?.improvement || 0} positions)\n\n:link: *Backlink Profile*\n• Total Backlinks: ${backlinkSummary.total_backlinks || 0}\n• Referring Domains: ${backlinkSummary.referring_domains || 0}\n• New This Month: ${backlinkSummary.new_last_30_days || 0}`
};

return [{ json: report }];
